+ * @file /src/lib/sleep_win.cpp
+ *
+ * @brief Implementation of the sleep classes.
+ *
+ * @date April 2013
+ **/
+/*****************************************************************************
+** Platform Check
+*****************************************************************************/
+
+#include <ecl/config.hpp>
